import anthropic
import json

client = anthropic.Anthropic()

# 1. System prompt
SYSTEM = """
You are a customer support agent for an e-commerce platform.

Tools available:
- get_order: look up an order by ID
- update_order_status: update an order's status (use only for cancellations)
- search_faq: search the help centre for answers

When you have a complete answer, call task_complete.
"""

# 2. Tools
def get_order(order_id: str) -> str:
    orders = {"ORD-42": {"status": "shipped", "eta": "2024-06-15", "total": 59.99}}
    return json.dumps(orders.get(order_id, {"error": "not found"}))

def update_order_status(order_id: str, status: str) -> str:
    if status not in ("cancelled",):
        return json.dumps({"ok": False, "error": "Only cancellations permitted."})
    return json.dumps({"ok": True, "order_id": order_id, "new_status": status})

def search_faq(query: str) -> str:
    return json.dumps({"results": [
        {"q": "How do I track my order?", "a": "Use the tracking link in your confirmation email."}
    ]})

TOOLS = [
    {"name": "get_order", "description": "Look up order details by order ID.",
     "input_schema": {"type": "object", "properties": {"order_id": {"type": "string"}}, "required": ["order_id"]}},
    {"name": "update_order_status", "description": "Cancel an order. Only call for confirmed cancellations.",
     "input_schema": {"type": "object", "properties": {"order_id": {"type": "string"}, "status": {"type": "string", "enum": ["cancelled"]}}, "required": ["order_id", "status"]}},
    {"name": "search_faq", "description": "Search FAQ for answers to common questions.",
     "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}},
    {"name": "task_complete", "description": "Call when the customer's question is fully answered.",
     "input_schema": {"type": "object", "properties": {"answer": {"type": "string"}}, "required": ["answer"]}},
]

DISPATCH = {
    "get_order": get_order,
    "update_order_status": update_order_status,
    "search_faq": search_faq,
}

# 3 & 4. Message history + loop controller
def run_support_agent(user_message: str, max_iterations: int = 10) -> str:
    messages = [{"role": "user", "content": user_message}]

    for _ in range(max_iterations):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=SYSTEM,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})

        tool_calls = [b for b in resp.content if b.type == "tool_use"]
        if not tool_calls:
            break

        results = []
        for block in tool_calls:
            if block.name == "task_complete":
                return block.input["answer"]
            fn = DISPATCH.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": f"Unknown: {block.name}"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})

        messages.append({"role": "user", "content": results})

    return "I was unable to fully resolve your question. Please contact support."

answer = run_support_agent("Where is my order ORD-42?")
print(answer)

import anthropic
import json

client = anthropic.Anthropic()

def run_agent_with_budget(
    system: str,
    tools: list,
    dispatch: dict,
    user_message: str,
    max_iterations: int = 15,
    token_budget: int = 50_000,
) -> dict:
    messages = [{"role": "user", "content": user_message}]
    total_input_tokens = 0

    for iteration in range(1, max_iterations + 1):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=system,
            tools=tools,
            messages=messages,
        )
        total_input_tokens += resp.usage.input_tokens
        messages.append({"role": "assistant", "content": resp.content})

        # Budget gate — checked AFTER the call (cost is already spent for this round)
        if total_input_tokens > token_budget:
            return {
                "status": "budget_exceeded",
                "iterations": iteration,
                "total_input_tokens": total_input_tokens,
            }

        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name == "task_complete":
                return {
                    "status": "complete",
                    "answer": block.input["answer"],
                    "iterations": iteration,
                    "total_input_tokens": total_input_tokens,
                }
            if block.name == "task_failed":
                return {
                    "status": "failed",
                    "reason": block.input["reason"],
                    "iterations": iteration,
                    "total_input_tokens": total_input_tokens,
                }

        if not tool_calls:
            return {"status": "stuck", "iterations": iteration, "total_input_tokens": total_input_tokens}

        results = []
        for block in tool_calls:
            fn = dispatch.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": f"Unknown: {block.name}"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

    return {"status": "max_iterations", "iterations": max_iterations, "total_input_tokens": total_input_tokens}

import json
import anthropic

client = anthropic.Anthropic()

def extract_run_log(messages: list, outcome: dict) -> dict:
    """
    Build a structured log entry from a completed agent run.
    Extracts Thought text, tool calls, and tool results into a flat list.
    """
    steps = []
    for msg in messages:
        role = msg["role"]
        content = msg["content"]

        if isinstance(content, str):
            steps.append({"role": role, "type": "text", "text": content})
            continue

        for block in content:
            if isinstance(block, dict):
                btype = block.get("type")
                if btype == "text":
                    steps.append({"role": role, "type": "thought", "text": block.get("text", "")})
                elif btype == "tool_use":
                    steps.append({
                        "role": role,
                        "type": "tool_call",
                        "tool": block["name"],
                        "input": block["input"],
                        "id": block["id"],
                    })
                elif btype == "tool_result":
                    steps.append({
                        "role": role,
                        "type": "observation",
                        "tool_use_id": block["tool_use_id"],
                        "content": block["content"],
                    })
            else:
                # SDK object — access attributes
                if block.type == "text":
                    steps.append({"role": role, "type": "thought", "text": block.text})
                elif block.type == "tool_use":
                    steps.append({
                        "role": role, "type": "tool_call",
                        "tool": block.name, "input": block.input, "id": block.id,
                    })

    return {
        "status": outcome.get("status"),
        "answer": outcome.get("answer"),
        "iterations": outcome.get("iterations"),
        "total_input_tokens": outcome.get("total_input_tokens"),
        "steps": steps,
    }

